  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    ...
  ]);
});
```

The endpoint returns PII (names + email addresses) with **no authentication, no authorization, and no rate limiting**. Even with test data today, this pattern will ship to production and leak real users' data. It's also scrape-friendly.

**Fix:** require auth and scope the response:
```js
const requireAuth = (req, res, next) => {
  const token = req.headers.authorization?.replace('Bearer ', '');
  if (!token || !verifyJwt(token)) return res.status(401).json({ error: 'Unauthorized' });
  req.user = decodeJwt(token);
  next();
};

app.get('/users', requireAuth, (req, res) => {
  // Return only what the caller is allowed to see, and omit email unless needed
  res.json(users.map(u => ({ id: u.id, name: u.name })));
});
```

---

